import{_ as o,o as e,c as a,a2 as r}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"2024年 · 最后的年度信","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-year/2024年.md","filePath":"05_quotes/by-year/2024年.md"}'),u={name:"05_quotes/by-year/2024年.md"};function l(q,t,c,p,s,_){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="_2024年-·-最后的年度信" tabindex="-1">2024年 · 最后的年度信 <a class="header-anchor" href="#_2024年-·-最后的年度信" aria-label="Permalink to &quot;2024年 · 最后的年度信&quot;">​</a></h1><blockquote><p>&quot;我这辈子最幸运的事，是很早就找到了我最热爱的工作。每天去办公室，就像去赴一场约会——而且还有人付钱给你。&quot;——巴菲特（94岁）</p></blockquote><p>本页收录2024年<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>年报中的经典语录。这是巴菲特60年投资生涯倒数第二封致股东信，由94岁的他亲笔写就，字里行间尽是一位智者对投资者的最后叮嘱。</p><hr><h2 id="核心金句" tabindex="-1">核心金句 <a class="header-anchor" href="#核心金句" aria-label="Permalink to &quot;核心金句&quot;">​</a></h2><blockquote><p>&quot;我这辈子最幸运的事，是很早就找到了我最热爱的工作。每天去办公室，就像去赴一场约会——而且还有人付钱给你。&quot;</p></blockquote><blockquote><p>&quot;巴菲特遗产计划很简单：99%以上的财富将捐给慈善机构。我没有复杂的慈善架构，就是简单的现金捐赠。&quot;</p></blockquote><blockquote><p>&quot;在评估管理者时，我从不看候选人上过什么学校。伟大的管理者可能毕业于名校，也可能是像皮特·利格尔那样，学历不高但天赋异禀。天分的作用远大于后天培养。&quot;</p></blockquote><blockquote><p>&quot;错误会逐渐消退；成功的决策可以永远绽放光彩。这就是为什么，找到好的管理者比找到一个好的收购时机更重要。&quot;</p></blockquote><blockquote><p>&quot;我一生中最幸运的三件事：1951年遇到GEICO、1986年遇到阿吉特·贾恩、以及1959年遇到查理·芒格。&quot;</p></blockquote><blockquote><p>&quot;格雷格·阿贝尔接任后，会以同样的坦诚和原则来写这封信。伯克希尔的文化比任何个人都重要。&quot;</p></blockquote><blockquote><p>&quot;保险业务对伯克希尔至关重要，值得持续关注。2024年GEICO在托德·科姆斯的改造下，核保效率大幅提升。这是一颗需要大力抛光的长期宝石。&quot;</p></blockquote><blockquote><p>&quot;忘掉&#39;最大化&#39;这个词。真正重要的是：找到一个你真正理解的业务，以合理的价格买入，然后长期持有。这就是伯克希尔60年教会我的全部。&quot;</p></blockquote><hr><h2 id="本年背景" tabindex="-1">本年背景 <a class="header-anchor" href="#本年背景" aria-label="Permalink to &quot;本年背景&quot;">​</a></h2><p>2024年，巴菲特94岁。这是他最后一次以CEO身份系统撰写年度致股东信（2025年的信由阿贝尔接笔）。94岁的他在信中深情回顾了伯克希尔60年的投资历程，特别提及了三位最重要的伙伴：皮特·利格尔（森林河公司创始人，年薪10万美元+10%奖金直到退休）、格雷格·阿贝尔（继任CEO），以及&quot;老朋友&quot;查理·芒格。</p><p>伯克希尔2024年经营收益474亿美元，保险业务大幅改善，浮存金依然是帝国最核心的结构性资产。</p><hr><h2 id="深入阅读" tabindex="-1">深入阅读 <a class="header-anchor" href="#深入阅读" aria-label="Permalink to &quot;深入阅读&quot;">​</a></h2><p><a href="/01_letters/2024年/翻译.html">01_letters/2024年/翻译</a> · <a href="/01_letters/2024年/核心总结.html">01_letters/2024年/核心总结</a> · <a href="/01_letters/2024年/思维导图.html">01_letters/2024年/思维导图</a></p>',20)])])}const n=o(u,[["render",l]]);export{b as __pageData,n as default};
